inline bool VerifyMessagePayload(::flatbuffers::Verifier &verifier, const void *obj, MessagePayload type) {
  switch (type) {
    case MessagePayload::NONE: {
      return true;
    }
    case MessagePayload::RpcCall: {
      auto ptr = reinterpret_cast<const ChaosEngine::RpcCall *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::RpcResponse: {
      auto ptr = reinterpret_cast<const ChaosEngine::RpcResponse *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::ReplicationMessage: {
      auto ptr = reinterpret_cast<const ChaosEngine::ReplicationMessage *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::EntityFullSync: {
      auto ptr = reinterpret_cast<const ChaosEngine::EntityFullSync *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::EntityLeave: {
      auto ptr = reinterpret_cast<const ChaosEngine::EntityLeave *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::MergedMessage: {
      auto ptr = reinterpret_cast<const ChaosEngine::MergedMessage *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyMessagePayloadVector(::flatbuffers::Verifier &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<MessagePayload> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyMessagePayload(
        verifier,  values->Get(i), types->GetEnum<MessagePayload>(i))) {
      return false;
    }
  }
  return true;
}

inline void *MessagePayloadUnion::UnPack(const void *obj, MessagePayload type, const ::flatbuffers::resolver_function_t *resolver) {
  (void)resolver;
  switch (type) {
    case MessagePayload::RpcCall: {
      auto ptr = reinterpret_cast<const ChaosEngine::RpcCall *>(obj);
      return ptr->UnPack(resolver);
    }
    case MessagePayload::RpcResponse: {
      auto ptr = reinterpret_cast<const ChaosEngine::RpcResponse *>(obj);
      return ptr->UnPack(resolver);
    }
    case MessagePayload::ReplicationMessage: {
      auto ptr = reinterpret_cast<const ChaosEngine::ReplicationMessage *>(obj);
      return ptr->UnPack(resolver);
    }
    case MessagePayload::EntityFullSync: {
      auto ptr = reinterpret_cast<const ChaosEngine::EntityFullSync *>(obj);
      return ptr->UnPack(resolver);
    }
    case MessagePayload::EntityLeave: {
      auto ptr = reinterpret_cast<const ChaosEngine::EntityLeave *>(obj);
      return ptr->UnPack(resolver);
    }
    case MessagePayload::MergedMessage: {
      auto ptr = reinterpret_cast<const ChaosEngine::MergedMessage *>(obj);
      return ptr->UnPack(resolver);
    }
    default: return nullptr;
  }
}

inline ::flatbuffers::Offset<void> MessagePayloadUnion::Pack(::flatbuffers::FlatBufferBuilder &_fbb, const ::flatbuffers::rehasher_function_t *_rehasher) const {
  (void)_rehasher;
  switch (type) {
    case MessagePayload::RpcCall: {
      auto ptr = reinterpret_cast<const ChaosEngine::RpcCallT *>(value);
      return CreateRpcCall(_fbb, ptr, _rehasher).Union();
    }
    case MessagePayload::RpcResponse: {
      auto ptr = reinterpret_cast<const ChaosEngine::RpcResponseT *>(value);
      return CreateRpcResponse(_fbb, ptr, _rehasher).Union();
    }
    case MessagePayload::ReplicationMessage: {
      auto ptr = reinterpret_cast<const ChaosEngine::ReplicationMessageT *>(value);
      return CreateReplicationMessage(_fbb, ptr, _rehasher).Union();
    }
    case MessagePayload::EntityFullSync: {
      auto ptr = reinterpret_cast<const ChaosEngine::EntityFullSyncT *>(value);
      return CreateEntityFullSync(_fbb, ptr, _rehasher).Union();
    }
    case MessagePayload::EntityLeave: {
      auto ptr = reinterpret_cast<const ChaosEngine::EntityLeaveT *>(value);
      return CreateEntityLeave(_fbb, ptr, _rehasher).Union();
    }
    case MessagePayload::MergedMessage: {
      auto ptr = reinterpret_cast<const ChaosEngine::MergedMessageT *>(value);
      return CreateMergedMessage(_fbb, ptr, _rehasher).Union();
    }
    default: return 0;
  }
}

inline MessagePayloadUnion::MessagePayloadUnion(const MessagePayloadUnion &u) : type(u.type), value(nullptr) {
  switch (type) {
    case MessagePayload::RpcCall: {
      value = new ChaosEngine::RpcCallT(*reinterpret_cast<ChaosEngine::RpcCallT *>(u.value));
      break;
    }
    case MessagePayload::RpcResponse: {
      value = new ChaosEngine::RpcResponseT(*reinterpret_cast<ChaosEngine::RpcResponseT *>(u.value));
      break;
    }
    case MessagePayload::ReplicationMessage: {
      value = new ChaosEngine::ReplicationMessageT(*reinterpret_cast<ChaosEngine::ReplicationMessageT *>(u.value));
      break;
    }
    case MessagePayload::EntityFullSync: {
      value = new ChaosEngine::EntityFullSyncT(*reinterpret_cast<ChaosEngine::EntityFullSyncT *>(u.value));
      break;
    }
    case MessagePayload::EntityLeave: {
      value = new ChaosEngine::EntityLeaveT(*reinterpret_cast<ChaosEngine::EntityLeaveT *>(u.value));
      break;
    }
    case MessagePayload::MergedMessage: {
      value = new ChaosEngine::MergedMessageT(*reinterpret_cast<ChaosEngine::MergedMessageT *>(u.value));
      break;
    }
    default:
      break;
  }
}

inline void MessagePayloadUnion::Reset() {
  switch (type) {
    case MessagePayload::RpcCall: {
      auto ptr = reinterpret_cast<ChaosEngine::RpcCallT *>(value);
      delete ptr;
      break;
    }
    case MessagePayload::RpcResponse: {
      auto ptr = reinterpret_cast<ChaosEngine::RpcResponseT *>(value);
      delete ptr;
      break;
    }
    case MessagePayload::ReplicationMessage: {
      auto ptr = reinterpret_cast<ChaosEngine::ReplicationMessageT *>(value);
      delete ptr;
      break;
    }
    case MessagePayload::EntityFullSync: {
      auto ptr = reinterpret_cast<ChaosEngine::EntityFullSyncT *>(value);
      delete ptr;
      break;
    }
    case MessagePayload::EntityLeave: {
      auto ptr = reinterpret_cast<ChaosEngine::EntityLeaveT *>(value);
      delete ptr;
      break;
    }
    case MessagePayload::MergedMessage: {
      auto ptr = reinterpret_cast<ChaosEngine::MergedMessageT *>(value);
      delete ptr;
      break;
    }
    default: break;
  }
  value = nullptr;
  type = MessagePayload::NONE;
}

